// Content validation and platform preparation
const item = $input.first();
const content = item.json.content;
const platforms = item.json.platforms || [];
const domain = item.json.domain;
const contentId = item.json.content_id;

// Validate required fields
if (!content || !contentId) {
  throw new Error('Missing required content or content_id');
}

// Platform-specific content formatting requirements
const platformRequirements = {
  wordpress: {
    max_title_length: 60,
    max_excerpt_length: 160,
    supports_html: true,
    requires_featured_image: true,
    seo_optimization: true
  },
  medium: {
    max_title_length: 100,
    max_subtitle_length: 140,
    supports_html: true,
    markdown_preferred: true,
    requires_tags: true
  },
  linkedin: {
    max_title_length: 70,
    max_content_length: 3000,
    supports_html: false,
    requires_hashtags: true,
    professional_tone: true
  },
  twitter: {
    max_content_length: 280,
    supports_threads: true,
    requires_hashtags: true,
    optimal_time_sensitive: true
  },
  facebook: {
    max_title_length: 40,
    optimal_content_length: 1200,
    supports_html: false,
    engagement_focused: true
  }
};

// Extract content elements
const lines = content.split('\n').filter(line => line.trim().length > 0);
const title = lines[0].replace(/^#+\s*/, '').trim(); // Remove markdown headers
const mainContent = lines.slice(1).join('\n').trim();

// Generate excerpt/summary
const words = mainContent.split(' ');
const excerpt = words.slice(0, 30).join(' ') + (words.length > 30 ? '...' : '');

// Domain-specific hashtags and categories
const domainHashtags = {
  finance: ['#Finance', '#Investment', '#MarketAnalysis', '#Economy', '#Trading'],
  sports: ['#Sports', '#Athletics', '#GameAnalysis', '#SportsNews', '#Performance'],
  technology: ['#Technology', '#Innovation', '#TechNews', '#DigitalTransformation', '#AI'],
  general: ['#News', '#Analysis', '#Insights', '#Trending', '#Update']
};

const hashtags = domainHashtags[domain] || domainHashtags.general;

// Create publishing jobs for each platform
const publishingJobs = [];

for (const platform of platforms) {
  const requirements = platformRequirements[platform];
  if (!requirements) continue;

  let formattedContent = {
    platform: platform,
    content_id: contentId,
    original_content: content,
    domain: domain
  };

  // Platform-specific formatting
  switch (platform) {
    case 'wordpress':
      formattedContent = {
        ...formattedContent,
        title: title.substring(0, requirements.max_title_length),
        content: mainContent,
        excerpt: excerpt.substring(0, requirements.max_excerpt_length),
        category: domain,
        tags: hashtags.map(tag => tag.replace('#', '')),
        status: 'publish',
        format: 'standard'
      };
      break;

    case 'medium':
      formattedContent = {
        ...formattedContent,
        title: title.substring(0, requirements.max_title_length),
        content: mainContent,
        contentFormat: 'markdown',
        tags: hashtags.map(tag => tag.replace('#', '')).slice(0, 5),
        publishStatus: 'public',
        license: 'all-rights-reserved'
      };
      break;

    case 'linkedin':
      // LinkedIn requires more concise content
      const linkedinContent = mainContent.length > requirements.max_content_length 
        ? mainContent.substring(0, requirements.max_content_length - 50) + '... (continued in comments)'
        : mainContent;

      formattedContent = {
        ...formattedContent,
        content: `${title}\n\n${linkedinContent}\n\n${hashtags.slice(0, 5).join(' ')}`,
        visibility: 'PUBLIC'
      };
      break;

    case 'twitter':
      // Create Twitter thread if content is long
      const maxTweetLength = requirements.max_content_length - 50; // Reserve space for hashtags
      const tweets = [];

      // First tweet with title
      tweets.push(`${title} ${hashtags.slice(0, 3).join(' ')} (1/n)`);

      // Split content into tweets
      const contentWords = mainContent.split(' ');
      let currentTweet = '';
      let tweetCount = 2;

      for (const word of contentWords) {
        if ((currentTweet + ' ' + word).length <= maxTweetLength) {
          currentTweet += (currentTweet ? ' ' : '') + word;
        } else {
          tweets.push(`${currentTweet} (${tweetCount}/n)`);
          currentTweet = word;
          tweetCount++;
        }
      }

      if (currentTweet) {
        tweets.push(`${currentTweet} (${tweetCount}/n)`);
      }

      formattedContent = {
        ...formattedContent,
        tweets: tweets,
        thread: true
      };
      break;

    case 'facebook':
      const fbContent = `${title}\n\n${mainContent}`;
      formattedContent = {
        ...formattedContent,
        message: fbContent.length > 1200 ? fbContent.substring(0, 1200) + '...' : fbContent,
        link: '', // Will be filled with published URL
        privacy: 'EVERYONE'
      };
      break;
  }

  publishingJobs.push({
    json: {
      ...formattedContent,
      scheduled_time: new Date().toISOString(),
      priority: 'normal',
      retry_count: 0,
      max_retries: 3
    }
  });
}

return publishingJobs;

// Intelligent publishing schedule optimization
const items = $input.all();
const processedItems = [];

// Platform-specific optimal posting times (UTC)
const optimalTimes = {
  wordpress: {
    weekdays: [9, 14, 16], // 9 AM, 2 PM, 4 PM
    weekends: [10, 15]
  },
  medium: {
    weekdays: [8, 13, 17], // 8 AM, 1 PM, 5 PM  
    weekends: [11, 16]
  },
  linkedin: {
    weekdays: [8, 12, 17, 18], // Business hours focus
    weekends: [10, 14]
  },
  twitter: {
    weekdays: [9, 12, 15, 17, 19], // Multiple daily peaks
    weekends: [10, 13, 16, 20]
  },
  facebook: {
    weekdays: [13, 15, 19], // Afternoon and evening
    weekends: [12, 14, 16]
  }
};

// Calculate next optimal posting time for each platform
function getNextOptimalTime(platform, currentTime = new Date()) {
  const times = optimalTimes[platform];
  if (!times) return currentTime;

  const now = new Date(currentTime);
  const isWeekend = now.getDay() === 0 || now.getDay() === 6;
  const applicableTimes = isWeekend ? times.weekends : times.weekdays;

  // Find next optimal time today
  const currentHour = now.getUTCHours();
  const todayTimes = applicableTimes.filter(hour => hour > currentHour);

  if (todayTimes.length > 0) {
    // Use next optimal time today
    const nextHour = todayTimes[0];
    const scheduledTime = new Date(now);
    scheduledTime.setUTCHours(nextHour, Math.floor(Math.random() * 15), 0, 0); // Random minutes 0-15
    return scheduledTime;
  } else {
    // Schedule for tomorrow's first optimal time
    const tomorrow = new Date(now);
    tomorrow.setUTCDate(tomorrow.getUTCDate() + 1);
    const tomorrowIsWeekend = tomorrow.getDay() === 0 || tomorrow.getDay() === 6;
    const tomorrowTimes = tomorrowIsWeekend ? times.weekends : times.weekdays;

    tomorrow.setUTCHours(tomorrowTimes[0], Math.floor(Math.random() * 15), 0, 0);
    return tomorrow;
  }
}

// Add spacing between similar content types
const platformSchedules = {};

for (const item of items) {
  const platform = item.json.platform;
  const domain = item.json.domain;

  if (!platformSchedules[platform]) {
    platformSchedules[platform] = [];
  }

  // Get optimal time
  const baseTime = getNextOptimalTime(platform);

  // Add spacing for same domain content (15-30 minutes apart)
  const samedomainCount = platformSchedules[platform].filter(p => p.domain === domain).length;
  const spacingMinutes = 15 + (samedomainCount * 15);

  const scheduledTime = new Date(baseTime.getTime() + (spacingMinutes * 60000));

  platformSchedules[platform].push({
    domain: domain,
    scheduledTime: scheduledTime
  });

  processedItems.push({
    json: {
      ...item.json,
      scheduled_time: scheduledTime.toISOString(),
      optimal_timing: true,
      spacing_applied: spacingMinutes,
      publishing_strategy: 'optimized_timing'
    }
  });
}

return processedItems;

// Advanced error analysis and retry strategy
const item = $input.first();
const error = item.json.error || {};
const platform = item.json.platform;
const retryCount = (item.json.retry_count || 0) + 1;
const maxRetries = item.json.max_retries || 3;

// Categorize error types for different retry strategies
const errorCategories = {
  rate_limit: ['rate limit', 'too many requests', '429'],
  authentication: ['unauthorized', 'authentication', 'token', '401'],
  server_error: ['internal server error', '500', '502', '503', '504'],
  content_issue: ['content', 'validation', 'format', '400'],
  network: ['timeout', 'connection', 'network']
};

function categorizeError(errorMessage) {
  const message = errorMessage.toLowerCase();
  for (const [category, keywords] of Object.entries(errorCategories)) {
    if (keywords.some(keyword => message.includes(keyword))) {
      return category;
    }
  }
  return 'unknown';
}

const errorCategory = categorizeError(error.message || '');

// Define retry strategies based on error type
const retryStrategies = {
  rate_limit: {
    should_retry: retryCount <= maxRetries,
    wait_time: Math.pow(2, retryCount) * 60000, // Exponential backoff in minutes
    modification_needed: false
  },
  authentication: {
    should_retry: retryCount <= 2, // Limited retries for auth issues
    wait_time: 30000, // 30 seconds
    modification_needed: true,
    modification_type: 'refresh_credentials'
  },
  server_error: {
    should_retry: retryCount <= maxRetries,
    wait_time: Math.pow(2, retryCount) * 30000, // Exponential backoff
    modification_needed: false
  },
  content_issue: {
    should_retry: retryCount <= 2,
    wait_time: 10000,
    modification_needed: true,
    modification_type: 'reformat_content'
  },
  network: {
    should_retry: retryCount <= maxRetries,
    wait_time: 15000 * retryCount, // Linear backoff
    modification_needed: false
  },
  unknown: {
    should_retry: retryCount <= Math.min(2, maxRetries),
    wait_time: 30000,
    modification_needed: false
  }
};

const strategy = retryStrategies[errorCategory];

// Calculate next retry time
const nextRetryTime = new Date(Date.now() + strategy.wait_time);

// Prepare retry payload
const retryData = {
  ...item.json,
  retry_count: retryCount,
  error_category: errorCategory,
  error_message: error.message,
  next_retry_time: nextRetryTime.toISOString(),
  should_retry: strategy.should_retry,
  modification_needed: strategy.modification_needed,
  modification_type: strategy.modification_type || null,
  retry_strategy: errorCategory
};

// Content modifications for specific error types
if (strategy.modification_needed && strategy.modification_type === 'reformat_content') {
  if (platform === 'twitter' && item.json.tweets) {
    // Shorten tweets if too long
    retryData.tweets = item.json.tweets.map(tweet => 
      tweet.length > 250 ? tweet.substring(0, 247) + '...' : tweet
    );
  } else if (platform === 'linkedin' && item.json.content) {
    // Ensure LinkedIn content meets requirements
    retryData.content = item.json.content.substring(0, 2900) + '...';
  }
}

return [{
  json: retryData
}];

// Performance tracking and cross-platform correlation
const successfulPublications = $input.all();
const performanceData = [];

for (const publication of successfulPublications) {
  const pub = publication.json;

  performanceData.push({
    content_id: pub.content_id,
    platform: pub.platform,
    domain: pub.domain,
    publication_id: pub.publication_id,
    publication_url: pub.publication_url,
    scheduled_time: pub.scheduled_time,
    actual_publish_time: pub.published_at,
    optimal_timing_used: pub.optimal_timing || false,
    publishing_delay: pub.published_at && pub.scheduled_time ? 
      new Date(pub.published_at).getTime() - new Date(pub.scheduled_time).getTime() : 0
  });
}

// Calculate batch metrics
const batchMetrics = {
  total_publications: performanceData.length,
  platforms_used: [...new Set(performanceData.map(p => p.platform))],
  domains_covered: [...new Set(performanceData.map(p => p.domain))],
  average_delay: performanceData.reduce((sum, p) => sum + (p.publishing_delay || 0), 0) / performanceData.length,
  optimal_timing_percentage: (performanceData.filter(p => p.optimal_timing_used).length / performanceData.length) * 100
};

return [{
  json: {
    batch_id: `batch_${Date.now()}`,
    performance_data: performanceData,
    batch_metrics: batchMetrics,
    timestamp: new Date().toISOString()
  }
}];
